import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type ColorPickerProps = IconProps;

const ColorPickerLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="m11.95 7.801 2.092-2.094a1.035 1.035 0 0 0 .006-1.474l-1.72-1.72c-.41-.41-1.033-.473-1.442-.056L8.74 4.591m3.21 3.21-3.21-3.21m3.21 3.21L6.8 12.94 3.047 14.08a.5.5 0 0 1-.623-.625L3.56 9.759l5.18-5.168"
      stroke="#6C707E"
      strokeMiterlimit="10"
    />
    <rect
      x="7.531"
      y="2.617"
      width="9.014"
      height="1"
      rx=".5"
      transform="rotate(45 7.531 2.617)"
      fill="#6C707E"
    />
  </svg>
);

const ColorPickerDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="m11.95 7.801 2.092-2.094a1.035 1.035 0 0 0 .006-1.474l-1.72-1.72c-.41-.41-1.033-.473-1.442-.056L8.74 4.591m3.21 3.21-3.21-3.21m3.21 3.21L6.8 12.94 3.047 14.08a.5.5 0 0 1-.623-.625L3.56 9.759l5.18-5.168"
      stroke="#CED0D6"
      strokeMiterlimit="10"
    />
    <rect
      x="7.531"
      y="2.617"
      width="9.014"
      height="1"
      rx=".5"
      transform="rotate(45 7.531 2.617)"
      fill="#CED0D6"
    />
  </svg>
);

export const ColorPicker: FC<ColorPickerProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? ColorPickerLight : ColorPickerDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
